#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>a(n),b(n);for(auto&x:a)scanf("%lld",&x);for(auto&x:b)scanf("%lld",&x);sort(a.begin(),a.end());sort(b.rbegin(),b.rend());long long s=0;for(int i=0;i<n;i++)s+=a[i]*b[i];printf("%lld\n",s);}
